import React from 'react'

const Hooks = () => {
    const [count, setCount] = React.useState(1);
    const handleIncrement = () => {
        setCount(count + 1);
    }
    const handleDecrement = () => {
        setCount(count - 1);
    }
  return (
    <div>
          <h1>Hooks</h1>
          <h2>{count}</h2>
          <button onClick={handleIncrement}>+</button>
          <button onClick={handleDecrement}>-</button>
          
    </div>
  )
}

export default Hooks
